    public partial class EmployeeContactService : BaseService<EmployeeContact>, IEmployeeContactService
    {
        public EmployeeContactService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task<EmployeeContact> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<EmployeeContact>().SingleAsync(
                predicate: x => x.ID == id,
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IPaginate<EmployeeContact>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<EmployeeContact>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.PersonName.Contains(search.Name)
                     || x.ContactNo.Contains(search.Name))
                     && x.EmployeeId == search.RefId.Value,
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "PersonName", ascending: !search.IsDescend);
        }
    }
